import time
from datetime import datetime
from sqlalchemy import Column, Integer, String, Boolean, Float, Text, BigInteger, JSON, DateTime
from app.database import Base

class User(Base):
    __tablename__ = "users"

    id = Column(Integer, primary_key=True, index=True)
    name = Column(String(255), nullable=False)
    email = Column(String(255), unique=True, index=True, nullable=False)
    password = Column(String(255), nullable=False)
    image = Column(Text, default="data:image/png;base64,", nullable=False)
    address = Column(JSON, default=dict)
    gender = Column(String(50), default="Not Selected")
    phone = Column(String(50), default="0000000")
    dob = Column(String(50), default="Not Selected")
    created_at = Column(DateTime, default=datetime.utcnow)

class Doctor(Base):
    __tablename__ = "doctors"

    id = Column(Integer, primary_key=True, index=True)
    name = Column(String(255), nullable=False)
    email = Column(String(255), unique=True, index=True, nullable=False)
    password = Column(String(255), nullable=False)
    image = Column(Text, nullable=False)
    speciality = Column(String(255), nullable=False)
    degree = Column(String(255), nullable=False)
    experience = Column(String(255), nullable=False)
    about = Column(Text, nullable=False)
    available = Column(Boolean, default=True)
    fee = Column(Float, nullable=False)
    address = Column(JSON, nullable=False)
    slots_booked = Column(JSON, default=dict)
    date = Column(BigInteger, nullable=False)
    created_at = Column(DateTime, default=datetime.utcnow)

class Appointment(Base):
    __tablename__ = "appointments"

    id = Column(Integer, primary_key=True, index=True)
    userId = Column(String(255), nullable=False)
    doctorId = Column(String(255), nullable=False)
    slotDate = Column(String(255), nullable=False)
    slotTime = Column(String(255), nullable=False)
    userData = Column(JSON, nullable=False)
    docData = Column(JSON, nullable=False)
    amount = Column(Float, nullable=False)
    date = Column(BigInteger, nullable=False)
    cancelled = Column(Boolean, default=False)
    payment = Column(Boolean, default=False)
    isCompleted = Column(Boolean, default=False)
    created_at = Column(DateTime, default=datetime.utcnow)

class Ticket(Base):
    __tablename__ = "tickets"

    id = Column(Integer, primary_key=True, index=True)
    userId = Column(String(255), nullable=False)
    userName = Column(String(255), nullable=False)
    userEmail = Column(String(255), nullable=False)
    subject = Column(String(255), nullable=False)
    description = Column(Text, nullable=False)
    category = Column(String(255), nullable=False)
    priority = Column(String(50), default="medium")  # low, medium, high
    status = Column(String(50), default="open")      # open, assigned, resolved
    assignedTo = Column(String(255), nullable=True)   # admin or doctor email
    response = Column(Text, nullable=True)
    created_at = Column(DateTime, default=datetime.utcnow)
    updated_at = Column(DateTime, default=datetime.utcnow, onupdate=datetime.utcnow)
